/**
 * Subscription Module Definition
 *
 * Core subscription management module for E-Menum.
 * Provides plan management, billing, and feature gating functionality.
 *
 * This is a CORE module - it cannot be disabled.
 *
 * @module modules/_core/subscription/subscription.module
 *
 * @example
 * ```typescript
 * import { SubscriptionModule } from '@/modules/_core/subscription/subscription.module';
 *
 * // Module is automatically discovered and loaded by ModuleLoader
 * // Access module instance via DI container
 * ```
 */

import { injectable, inject } from 'tsyringe';
import { TOKENS, registerSingleton, appContainer } from '@/core/kernel/container';
import type { ModuleInstance } from '@/core/kernel/module-loader';
import type { EventService } from '@/core/services/event.service';

import { SubscriptionController } from '@/modules/_core/subscription/subscription.controller';
import { SubscriptionService } from '@/modules/_core/subscription/subscription.service';
import { SubscriptionRepository } from '@/modules/_core/subscription/subscription.repository';
import { subscriptionRoutes } from '@/modules/_core/subscription/subscription.routes';
import type { SubscriptionModuleSettings } from '@/modules/_core/subscription/subscription.types';

// -----------------------------------------------------------------------------
// Module Types
// -----------------------------------------------------------------------------

/**
 * Subscription module context for lifecycle hooks
 */
export interface SubscriptionModuleContext {
  /** Event service for pub/sub */
  events: EventService;
  /** Module settings */
  settings: SubscriptionModuleSettings;
  /** Logger function */
  log: (message: string) => void;
}

/**
 * Subscription module hook definitions
 */
export interface SubscriptionModuleHooks {
  /** Called before subscription creation */
  beforeCreate?: (data: { organizationId: string; planId: string }) => Promise<void>;
  /** Called after subscription creation */
  afterCreate?: (data: { subscriptionId: string }) => Promise<void>;
  /** Called before plan change */
  beforePlanChange?: (data: { subscriptionId: string; newPlanId: string }) => Promise<void>;
  /** Called after plan change */
  afterPlanChange?: (data: { subscriptionId: string; previousPlanId: string; newPlanId: string }) => Promise<void>;
  /** Called before subscription cancellation */
  beforeCancel?: (data: { subscriptionId: string }) => Promise<void>;
  /** Called after subscription cancellation */
  afterCancel?: (data: { subscriptionId: string }) => Promise<void>;
}

// -----------------------------------------------------------------------------
// Subscription Module Class
// -----------------------------------------------------------------------------

/**
 * Subscription Module
 *
 * Core module providing subscription and billing management for E-Menum.
 * Handles plan management, subscription lifecycle, and feature gating.
 *
 * Features:
 * - Plan management (list, compare, pricing)
 * - Subscription CRUD and lifecycle management
 * - Trial period handling
 * - Plan upgrades/downgrades with proration
 * - Feature gating based on plan
 * - Resource limit checking
 * - Invoice management
 *
 * @example
 * ```typescript
 * // Module is automatically loaded by ModuleLoader
 * // Use SubscriptionService for business logic
 * const subService = container.resolve('SubscriptionService');
 * const result = await subService.checkFeature(orgId, 'ai.contentGeneration');
 * ```
 */
@injectable()
export class SubscriptionModule implements ModuleInstance {
  // ---------------------------------------------------------------------------
  // Static Properties
  // ---------------------------------------------------------------------------

  /** Module ID */
  static readonly id = 'subscription';

  /** Module name */
  static readonly name = 'Subscription Module';

  /** Module version */
  static readonly version = '1.0.0';

  /** Is core module (cannot be disabled) */
  static readonly isCore = true;

  /** Module routes configuration */
  static readonly routes = subscriptionRoutes;

  /** Providers (services) to register */
  static readonly providers = [SubscriptionService, SubscriptionRepository];

  /** Controllers to register */
  static readonly controllers = [SubscriptionController];

  // ---------------------------------------------------------------------------
  // Instance Properties
  // ---------------------------------------------------------------------------

  /** Module hooks registry */
  private hooks: SubscriptionModuleHooks = {};

  /** Module initialized flag */
  private initialized = false;

  constructor(
    @inject(TOKENS.EventService) private readonly eventService: EventService
  ) {}

  // ---------------------------------------------------------------------------
  // ModuleInstance Lifecycle Hooks
  // ---------------------------------------------------------------------------

  /**
   * Called when module is loaded.
   * Registers services with DI container.
   */
  async onLoad(): Promise<void> {
    this.log('Loading subscription module...');

    // Register SubscriptionRepository with DI container
    if (!appContainer.isRegistered('SubscriptionRepository')) {
      registerSingleton('SubscriptionRepository', SubscriptionRepository);
    }

    // Register SubscriptionService with DI container
    if (!appContainer.isRegistered('SubscriptionService')) {
      registerSingleton('SubscriptionService', SubscriptionService);
    }

    this.log('Subscription module loaded');
  }

  /**
   * Called when module is enabled/activated.
   * Sets up event listeners and registers routes.
   */
  async onEnable(): Promise<void> {
    if (this.initialized) {
      this.log('Subscription module already initialized');
      return;
    }

    this.log('Enabling subscription module...');

    // Subscribe to relevant events
    this.setupEventListeners();

    this.initialized = true;
    this.log('Subscription module enabled');

    // Emit module activated event
    await this.eventService.emitCustom('module.activated', {
      moduleId: SubscriptionModule.id,
      timestamp: new Date().toISOString(),
    });
  }

  /**
   * Called when module is disabled/deactivated.
   * Core modules cannot be fully disabled, but this handles graceful pause.
   */
  async onDisable(): Promise<void> {
    this.log('Subscription module disable requested (core module - limited action)');

    // Core modules cannot be fully disabled
    // This would only be called during shutdown

    this.initialized = false;
    this.log('Subscription module disabled');
  }

  /**
   * Called when module is unloaded.
   * Cleans up resources.
   */
  async onUnload(): Promise<void> {
    this.log('Unloading subscription module...');

    // Clear hooks
    this.hooks = {};

    this.log('Subscription module unloaded');
  }

  // ---------------------------------------------------------------------------
  // ModuleInstance Interface Methods
  // ---------------------------------------------------------------------------

  /**
   * Returns module routes for registration with Express.
   *
   * @returns Route configuration array
   */
  getRoutes(): unknown[] {
    return [subscriptionRoutes];
  }

  /**
   * Returns module controllers for registration with routing-controllers.
   *
   * @returns Controller class array
   */
  getControllers(): unknown[] {
    return SubscriptionModule.controllers;
  }

  // ---------------------------------------------------------------------------
  // Hook System
  // ---------------------------------------------------------------------------

  /**
   * Gets current module hooks.
   *
   * @returns Module hooks object
   */
  getHooks(): SubscriptionModuleHooks {
    return { ...this.hooks };
  }

  /**
   * Registers a hook handler.
   *
   * @param hookName - Name of the hook
   * @param handler - Hook handler function
   *
   * @example
   * ```typescript
   * subModule.registerHook('afterPlanChange', async (data) => {
   *   console.log('Plan changed:', data.newPlanId);
   * });
   * ```
   */
  registerHook<K extends keyof SubscriptionModuleHooks>(
    hookName: K,
    handler: SubscriptionModuleHooks[K]
  ): void {
    this.hooks[hookName] = handler;
    this.log(`Registered hook: ${hookName}`);
  }

  /**
   * Unregisters a hook handler.
   *
   * @param hookName - Name of the hook to unregister
   */
  unregisterHook(hookName: keyof SubscriptionModuleHooks): void {
    delete this.hooks[hookName];
    this.log(`Unregistered hook: ${hookName}`);
  }

  /**
   * Executes a hook if registered.
   *
   * @param hookName - Name of the hook
   * @param data - Data to pass to the hook
   */
  async executeHook<K extends keyof SubscriptionModuleHooks>(
    hookName: K,
    data: Parameters<NonNullable<SubscriptionModuleHooks[K]>>[0]
  ): Promise<void> {
    const hook = this.hooks[hookName];
    if (hook) {
      try {
        await (hook as (data: typeof data) => Promise<void>)(data);
      } catch (error) {
        this.log(`Hook execution error (${hookName}): ${error instanceof Error ? error.message : 'Unknown error'}`);
      }
    }
  }

  // ---------------------------------------------------------------------------
  // Event Listeners
  // ---------------------------------------------------------------------------

  /**
   * Sets up event listeners for the subscription module.
   */
  private setupEventListeners(): void {
    // Listen for organization creation to create default subscription
    this.eventService.on('organization.created', async (payload) => {
      this.log(`Organization created event received: ${payload.organizationId}`);
      // Could auto-create a free subscription for new organizations
    });

    // Listen for payment success to update subscription status
    this.eventService.on('payment.success', async (payload) => {
      this.log(`Payment success event received for subscription: ${payload.subscriptionId}`);
      // Update subscription status to ACTIVE if was PAST_DUE
    });

    // Listen for payment failure
    this.eventService.on('payment.failed', async (payload) => {
      this.log(`Payment failed event received for subscription: ${payload.subscriptionId}`);
      // Update subscription status to PAST_DUE
    });

    this.log('Event listeners set up');
  }

  // ---------------------------------------------------------------------------
  // Module Settings
  // ---------------------------------------------------------------------------

  /**
   * Gets default module settings.
   *
   * @returns Default subscription module settings
   */
  static getDefaultSettings(): SubscriptionModuleSettings {
    return {
      trialDays: 14,
      gracePeriodDays: 7,
      defaultCurrency: 'TRY',
      autoRenew: true,
      sendRenewalReminders: true,
      reminderDays: [7, 3, 1],
    };
  }

  // ---------------------------------------------------------------------------
  // Utility Methods
  // ---------------------------------------------------------------------------

  /**
   * Logs a message with module prefix.
   *
   * @param message - Message to log
   */
  private log(message: string): void {
    // eslint-disable-next-line no-console
    console.log(`[SubscriptionModule] ${message}`);
  }

  /**
   * Checks if module is initialized.
   *
   * @returns True if module is initialized
   */
  isInitialized(): boolean {
    return this.initialized;
  }

  /**
   * Gets module metadata.
   *
   * @returns Module metadata object
   */
  static getMetadata() {
    return {
      id: SubscriptionModule.id,
      name: SubscriptionModule.name,
      version: SubscriptionModule.version,
      isCore: SubscriptionModule.isCore,
      routes: SubscriptionModule.routes,
      providers: SubscriptionModule.providers.map((p) => p.name),
      controllers: SubscriptionModule.controllers.map((c) => c.name),
    };
  }
}

// -----------------------------------------------------------------------------
// Module Exports
// -----------------------------------------------------------------------------

/**
 * Default export for module loader dynamic import
 */
export default SubscriptionModule;

/**
 * Export module metadata
 */
export const metadata = SubscriptionModule.getMetadata();
